<?php
namespace Tests\Feature\Hr;
use Illuminate\Support\Facades\Artisan; use Illuminate\Support\Facades\Schema; use Tests\TestCase;
class HrPhase3CMigrationsRollbackTest extends TestCase { use RefreshHrDatabase; public function test_advance_tables_exist():void{$this->assertTrue(Schema::hasColumns('hr_advances',['employee_id','requested_amount','installment_count','status','source_key','paid_at']));$this->assertTrue(Schema::hasColumns('hr_advance_transactions',['advance_id','type','amount','transaction_date','source_key','payload_hash']));} public function test_rollback_preserves_expenses():void{Artisan::call('migrate:rollback',['--step'=>4]);Artisan::call('migrate:rollback',['--step'=>4]);Artisan::call('migrate:rollback',['--step'=>5]);Artisan::call('migrate:rollback',['--step'=>3]);Artisan::call('migrate:rollback',['--step'=>5]);Artisan::call('migrate:rollback',['--step'=>6]);Artisan::call('migrate:rollback',['--step'=>2]);Artisan::call('migrate:rollback',['--step'=>4]);Artisan::call('migrate:rollback',['--step'=>2]);$this->assertFalse(Schema::hasTable('hr_advances'));$this->assertTrue(Schema::hasTable('hr_expenses'));} }
